window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["cdl-combination"] = window.COURSE_LANG["cdl-combination"] || {};
window.COURSE_LANG["cdl-combination"]["es"] = [
  {"id":1,"q":"Antes de retroceder bajo un remolque, las mordazas de la quinta rueda deben estar:","opts":["Abiertas y listas para recibir el kingpin","Soldadas y cerradas","Quitadas por completo","Llenas de agua"],"re":"Empieza el enganche con las mordazas abiertas y la quinta rueda engrasada e inclinada hacia atrás."},
  {"id":2,"q":"Al alinear el tractor para retroceder bajo un remolque, debes:","opts":["Retroceder en un ángulo cerrado","Alinearte de frente, justo enfrente del remolque","Acercarte de lado","Golpear el remolque con velocidad"],"re":"Coloca el tractor directamente enfrente del remolque; retroceder en ángulo puede empujar el remolque de lado."},
  {"id":3,"q":"Antes de retroceder bajo el remolque, las ruedas del remolque deben estar:","opts":["Calzadas para que el remolque no se mueva","Girando","Quitadas","Levantadas del suelo"],"re":"Calza las ruedas del remolque para que no ruede mientras retrocedes y enganchas."},
  {"id":4,"q":"La altura del remolque antes del enganche debe ajustarse de modo que el remolque esté:","opts":["Apoyado plano en el suelo","Inclinado hacia un lado","Tan alto como llegue el tren de aterrizaje","Levantado un poco para que suba cuando el tractor retroceda debajo"],"re":"Levanta el remolque lo justo para que la quinta rueda lo eleve un poco al entrar debajo; ajusta con el tren de aterrizaje."},
  {"id":5,"q":"Cuando la quinta rueda apenas toca el remolque, antes de retroceder del todo, debes:","opts":["Arrancar y marcharte","Subir el tren de aterrizaje","Asegurar el tractor con el freno de estacionamiento y ponerlo en neutral","Desconectar la batería"],"re":"Aplica el freno de estacionamiento y deja el tractor en neutral para que no se mueva mientras conectas líneas y revisas la altura."},
  {"id":6,"q":"¿Cuándo debes conectar las líneas de aire y suministrar aire al remolque?","opts":["Nunca durante el enganche","Solo después de conducir una milla","Después de subir el tren de aterrizaje","Antes de retroceder del todo, para poder probar los frenos del remolque"],"re":"Conecta las líneas de aire y eléctricas y carga el remolque para que sus frenos queden aplicados y se puedan probar antes del enganche final."},
  {"id":7,"q":"La prueba de tirón (tug test) se hace:","opts":["Tocando el claxon tres veces","Bloqueando los frenos del remolque y jalando suavemente hacia adelante contra el kingpin","Acelerando el motor en neutral","Sacudiendo el remolque con el tren de aterrizaje"],"re":"Con los frenos del remolque bloqueados, jala suave hacia adelante; el tractor no debe soltarse del remolque."},
  {"id":8,"q":"Tras una prueba de tirón exitosa, debes inspeccionar el enganche:","opts":["Pateando las llantas","Escuchando la radio","Mirando debajo con una linterna para ver una conexión firme","Revisando el medidor de combustible"],"re":"Bájate y usa una linterna para confirmar que las mordazas están cerradas sobre el kingpin y que no hay espacio entre las placas."},
  {"id":9,"q":"Una vez completado e inspeccionado el enganche, el tren de aterrizaje debe estar:","opts":["A media altura","Apenas tocando el suelo","Quitado del remolque","Subido por completo con la manivela asegurada"],"re":"Sube el tren de aterrizaje por completo y asegura la manivela; luego retira los calzos de las ruedas."},
  {"id":10,"q":"El primer paso al desenganchar es:","opts":["Colocar el equipo y aliviar la presión sobre las mordazas","Sacar el tractor rápido","Dejar caer el remolque sobre su nariz","Desconectar la batería"],"re":"Alinea el equipo recto y alivia la presión sobre las mordazas de la quinta rueda para que la palanca de liberación se mueva con facilidad."},
  {"id":11,"q":"Antes de bajar el tren de aterrizaje para desenganchar, debes:","opts":["Desinflar las llantas","Calzar las ruedas del remolque","Quitar la quinta rueda","Desconectar la dirección"],"re":"Calza las ruedas del remolque para que se quede en su sitio una vez separado del tractor."},
  {"id":12,"q":"Al desenganchar, el tren de aterrizaje debe bajarse hasta que:","opts":["Levante las ruedas traseras del tractor del suelo","Quede totalmente retraído","Apenas haga contacto y soporte el remolque","Quede quitado del remolque"],"re":"Baja el tren de aterrizaje hasta que apenas toque el suelo y empiece a soportar el remolque, no a levantar el tractor."},
  {"id":13,"q":"Después de desconectar las líneas de aire al desenganchar, debes:","opts":["Dejarlas arrastrando por el suelo","Tirarlas a la basura","Atarlas al parachoques con una cuerda","Guardar las glad hands en los acopladores ficticios o soportes"],"re":"Asegura las líneas desconectadas colgando las glad hands en los acopladores ficticios para que queden limpias y sin daño."},
  {"id":14,"q":"Para aplicar los frenos (de resorte) del remolque antes de salir, usas:","opts":["Pisar el pedal una vez","Acelerar el motor","Abrir un drenaje del tanque","El control de suministro de aire del remolque para cortar el aire al remolque"],"re":"Jala el control de suministro de aire del remolque para cortar el aire y aplicar los frenos de resorte y que se quede en su sitio."},
  {"id":15,"q":"Para liberar la quinta rueda al desenganchar:","opts":["Jalas la manija de liberación para destrabar la palanca de cierre","Cortas el kingpin","Bajas el tren de aterrizaje por completo","Drenas los tanques de aire"],"re":"Destraba la quinta rueda jalando la manija de liberación para que las mordazas se abran y suelten el kingpin."},
  {"id":16,"q":"Después de destrabar la quinta rueda, debes sacar el tractor:","opts":["De golpe y a gran velocidad","De lado, fuera del remolque","Parcialmente, para que el bastidor libere primero el kingpin","Retrocediendo más fuerte bajo el remolque"],"re":"Saca el tractor parcialmente hasta que la quinta rueda libere el kingpin, luego sal por completo de debajo del remolque."},
  {"id":17,"q":"Bajar del todo el tren de aterrizaje antes de desconectar es importante porque:","opts":["Se ve mejor","Ahorra combustible","Carga la batería","Soporta el peso del remolque una vez que el tractor sale"],"re":"El tren de aterrizaje debe cargar el peso del remolque para que este no caiga cuando se retire el tractor."},
  {"id":18,"q":"Las mordazas de cierre de la quinta rueda deben cerrarse alrededor de:","opts":["La cabeza del kingpin","El cuello (shank) del kingpin","El tren de aterrizaje","Las glad hands"],"re":"Un enganche correcto tiene las mordazas cerradas sobre el cuello del kingpin, no sobre la cabeza."},
  {"id":19,"q":"Un espacio entre las placas superior e inferior de la quinta rueda significa que:","opts":["El enganche es correcto","El remolque está vacío","El enganche es incorrecto y debe corregirse","El aire está totalmente cargado"],"re":"No debe haber espacio entre la placa del remolque y la quinta rueda; un hueco indica que el kingpin no está bien asentado."},
  {"id":20,"q":"Antes del enganche, la quinta rueda debe estar:","opts":["Engrasada e inclinada hacia atrás","Seca y oxidada","Pintada","Cubierta con una lona"],"re":"Engrasa la placa de la quinta rueda e inclínala hacia atrás para que el kingpin entre y el remolque vaya suave."},
  {"id":21,"q":"Inspeccionas el enganche cerrado con una linterna para asegurarte de que las mordazas:","opts":["Estén pintadas de amarillo","Estén abiertas","Falten","Estén cerradas y trabadas alrededor del kingpin"],"re":"Mira debajo del remolque para confirmar que las mordazas se cerraron y trabaron por completo sobre el cuello del kingpin."},
  {"id":22,"q":"¿Cuál de estas condiciones de la quinta rueda es insegura?","opts":["Placa bien engrasada","Mordazas trabadas sobre el cuello","Pernos de montaje sueltos o faltantes","Sin espacio entre las placas"],"re":"Sujetadores de montaje sueltos o faltantes, grietas o juego excesivo hacen insegura la quinta rueda."},
  {"id":23,"q":"Si las mordazas de la quinta rueda se cierran sobre la cabeza del kingpin en vez del cuello:","opts":["El enganche es más fuerte","El remolque podría soltarse","Mejora el frenado","Levanta el remolque"],"re":"Cerrar sobre la cabeza es un enganche falso que puede dejar que el remolque se separe del tractor."},
  {"id":24,"q":"El kingpin es la pieza que:","opts":["Drena los tanques de aire","Ilumina el tablero","Se traba en las mordazas de la quinta rueda","Dirige el remolque"],"re":"El kingpin del remolque entra en la quinta rueda, donde las mordazas se cierran a su alrededor para sujetar el remolque."},
  {"id":25,"q":"Las quintas ruedas deslizantes y los ganchos pintle deben revisarse por:","opts":["Grietas, holgura y piezas faltantes","Recepción de radio","Nivel de combustible","Solo presión de las llantas"],"re":"Inspecciona el montaje, los seguros y las piezas de las quintas ruedas deslizantes y los ganchos pintle por grietas, desgaste y herrajes faltantes."},
  {"id":26,"q":"Las dos líneas de aire entre el tractor y el remolque son:","opts":["Las líneas caliente y fría","La línea de servicio (control) y la de emergencia (suministro)","Las líneas de combustible y aceite","Las líneas izquierda y derecha"],"re":"La línea de servicio lleva la señal de aplicación del freno; la de emergencia suministra aire y controla los frenos de resorte del remolque."},
  {"id":27,"q":"Los acoples que conectan las líneas de aire del tractor y del remolque se llaman:","opts":["Ajustadores de holgura","Kingpins","Glad hands","Tren de aterrizaje"],"re":"Las glad hands son los acoples que unen las líneas de aire de servicio y de emergencia."},
  {"id":28,"q":"Si cruzas las líneas de aire de servicio y de emergencia:","opts":["Puedes quedarte sin frenos de servicio del remolque cuando los necesites","Mejora el frenado","El remolque va más alto","Se ahorra aire"],"re":"Cruzar las líneas puede dejarte sin frenos de servicio del remolque; el color y la forma ayudan a no confundirlas."},
  {"id":29,"q":"El botón de control de suministro de aire del remolque es:","opts":["Un botón verde redondo","Un botón azul cuadrado","Un botón blanco triangular","Un botón rojo de ocho lados"],"re":"La válvula de suministro de aire del remolque es un botón rojo de ocho lados (octágono) que empujas para dar aire al remolque."},
  {"id":30,"q":"Para suministrar aire al remolque:","opts":["Jalas el botón de suministro de aire del remolque","Empujas el botón de suministro de aire del remolque","Abres una válvula de drenaje","Pisas el claxon"],"re":"Empuja el botón rojo de suministro de aire del remolque para enviarle aire; jálalo para cortar el aire."},
  {"id":31,"q":"El botón de suministro de aire del remolque salta solo cuando la presión de aire del tractor baja a unos:","opts":["20 a 45 psi","75 a 90 psi","100 a 120 psi","Solo a 0 psi"],"re":"Si la presión del tractor baja a unos 20 a 45 psi, la válvula salta y aplica los frenos de emergencia del remolque."},
  {"id":32,"q":"La válvula de protección del tractor está diseñada para:","opts":["Inflar las llantas","Cargar la batería","Calentar la cabina","Mantener el aire en el tractor si el remolque se suelta o tiene una fuga grave"],"re":"La válvula de protección del tractor se cierra para conservar el aire del tractor y que aún tengas frenos si pierdes el remolque."},
  {"id":33,"q":"En muchos equipos, la glad hand de la línea de servicio tiene el color:","opts":["Naranja","Azul","Verde","Morado"],"re":"La línea de servicio (control) suele ser azul y la de emergencia (suministro) roja para no cruzarlas."},
  {"id":34,"q":"Jalar el control de suministro de aire del remolque estando estacionado:","opts":["Suelta los frenos del remolque","Sube el tren de aterrizaje","Aplica los frenos de resorte (emergencia) del remolque","Arranca el motor"],"re":"Jalar el control corta el aire del remolque y aplica sus frenos de resorte para mantenerlo en su sitio."},
  {"id":35,"q":"El desfase de trayectoria (off-tracking) significa que en una vuelta las ruedas traseras del remolque:","opts":["Siguen una trayectoria más amplia que el tractor","Siguen una trayectoria más corta que el tractor","Se levantan del suelo","Dejan de girar"],"re":"Las ruedas del remolque van por dentro de la trayectoria del tractor, así que debes abrirte lo suficiente para que el remolque libere."},
  {"id":36,"q":"Cuanto más largo es el vehículo combinado:","opts":["Menos se desfasa (off-track)","Más rápido puede tomar curvas","Más bajo es su centro de gravedad","Más se desfasa en las vueltas"],"re":"A mayor distancia entre los ejes del tractor y del remolque, el remolque corta más la curva y aumenta el off-tracking."},
  {"id":37,"q":"La mayoría de las volcaduras de camión ocurren porque el conductor:","opts":["Frenó demasiado suave","Iba demasiado rápido para una vuelta","Tenía el remolque vacío","Usó luces bajas"],"re":"Las volcaduras suelen deberse a tomar una curva o rampa demasiado rápido; reduce muy por debajo de la velocidad indicada."},
  {"id":38,"q":"Para reducir el riesgo de volcadura, debes mantener la carga:","opts":["Lo más alta posible","Suelta dentro del remolque","Baja y centrada","Toda de un lado"],"re":"Una carga baja y centrada baja el centro de gravedad y hace el equipo más estable en las curvas."},
  {"id":39,"q":"En una rampa de salida con curva, debes:","opts":["Acelerar a lo largo de la curva","Mantener tu velocidad de carretera","Frenar fuerte a la mitad de la curva","Reducir muy por debajo de la velocidad indicada de la rampa"],"re":"La velocidad indicada de la rampa aún puede ser demasiada para un equipo cargado; reduce antes de la curva para evitar la volcadura."},
  {"id":40,"q":"Un efecto tijera (jackknife) del remolque ocurre cuando las ruedas del remolque:","opts":["Giran más rápido que el tractor","Se bloquean y derrapan, lanzando el remolque hacia afuera","Se levantan del suelo","Dirigen el tractor"],"re":"Las ruedas del remolque bloqueadas y derrapando pierden tracción y dejan que el remolque se abra hacia un lado."},
  {"id":41,"q":"Si el remolque empieza a abrirse en un derrape, debes:","opts":["Frenar más fuerte","Acelerar bruscamente","Soltar los frenos para que las ruedas vuelvan a rodar","Jalar el botón de suministro de aire del remolque"],"re":"Soltar los frenos deja que las ruedas del remolque giren y recuperen tracción para que el remolque se enderece."},
  {"id":42,"q":"Un remolque vacío o con poca carga tiende a:","opts":["Agarrarse mejor al camino","Nunca hacer tijera","Detenerse siempre en menos distancia","Derrapar con más facilidad por tener menos tracción"],"re":"Con poco peso sobre las ruedas, un remolque vacío tiene menos tracción y sus frenos se bloquean más fácil."},
  {"id":43,"q":"Los remolques fabricados desde 1998 deben tener:","opts":["Frenos antibloqueo (ABS)","Estranguladores manuales","Pisos de madera","Ejes de dirección dobles"],"re":"Los remolques fabricados después del 1 de marzo de 1998 deben tener frenos antibloqueo."},
  {"id":44,"q":"En un remolque con ABS, una falla se indica con:","opts":["Una flecha verde","Una luz roja de kingpin","Una luz amarilla de ABS en el remolque","Ningún indicador"],"re":"Una luz amarilla de falla en el remolque indica un problema del ABS que debe repararse."},
  {"id":45,"q":"Si la luz de falla del ABS del remolque está encendida:","opts":["No tienes frenos","Aún tienes frenos normales pero pierdes la función antibloqueo","Debes abandonar el remolque","No puedes dirigir"],"re":"Conservas los frenos de servicio normales; solo se pierde la función antibloqueo, así que repárala."},
  {"id":46,"q":"Al inspeccionar un vehículo combinado, también debes revisar:","opts":["El sistema de enganche y las líneas de aire","La radio del remolque","Los asientos de pasajeros","El color de pintura del remolque"],"re":"Las revisiones de combinación agregan la quinta rueda, el kingpin, el enganche, el tren de aterrizaje y las líneas de aire del remolque a la inspección básica."},
  {"id":47,"q":"Durante la revisión de frenos de aire en una combinación, los frenos del remolque deben:","opts":["Nunca probarse","Desconectarse","Dejarse congelados","Probarse por aplicación y retención correctas"],"re":"Comprueba que los frenos del remolque apliquen y retengan, incluida la prueba de tirón, antes de conducir la combinación."},
  {"id":48,"q":"Al inspeccionar el tren de aterrizaje, buscas:","opts":["Un tanque de combustible lleno","Daños, piezas faltantes y que esté totalmente subido","Ventanas limpias","Un teléfono cargado"],"re":"Revisa que el tren de aterrizaje esté sin daños, sin piezas faltantes, totalmente subido y con la manivela asegurada."},
  {"id":49,"q":"Antes de conducir, las líneas de aire entre el tractor y el remolque deben revisarse por:","opts":["Fugas, desgaste y conexiones seguras de las glad hands","La estación de radio correcta","Una batería llena","La marca de las llantas"],"re":"Inspecciona las líneas de aire por fugas, grietas, partes desgastadas y que las glad hands estén acopladas y selladas."},
  {"id":50,"q":"Un vehículo combinado suele requerir más distancia de frenado porque:","opts":["Es más pesado y largo que un vehículo simple","Es más corto que un auto","No tiene frenos","Tiene un motor más pequeño"],"re":"Más peso y largo, más el retardo del freno, hacen que una combinación cargada necesite más distancia para detenerse."}
];
